parameters.jsCode:
const body = $input.first().json.body || $input.first().json;
const sessionId = (body.sessionId || '').trim().substring(0, 100);
const message = (body.message || '').trim().substring(0, 2000);
const companyId = (body.companyId || 'default').trim().substring(0, 100);

if (!sessionId || !message) {
  throw new Error('sessionId en message zijn verplicht');
}

return [{ json: { sessionId, message, companyId, timestamp: new Date().toISOString() } }];

const validated = $('Valideer Input').item.json;
const memoryRows = $('Lees Geheugen').all();
const knowledgeRows = $('Lees Bedrijfskennis').all();

// Conversatiegeschiedenis: omgekeerd ophalen → chronologisch
const history = memoryRows
  .map(r => r.json)
  .reverse()
  .map(r => ({ role: r.role, content: r.content }));

// Kennisbasis tekst
const knowledge = knowledgeRows
  .map(r => r.json)
  .map(r => `V: ${r.question}\nA: ${r.answer}`)
  .join('\n\n');

const systemPrompt = `Je bent een behulpzame assistent voor ${validated.companyId}.\n\nBEDRIJFSKENNIS:\n${knowledge || 'Geen specifieke kennis beschikbaar. Verwijs bij complexe vragen naar de klantenservice.'}\n\nINSTRUCTIES:\n- Antwoord altijd in de taal van de gebruiker\n- Houd antwoorden bondig en to-the-point\n- Als iemand een afspraak wil boeken, bevestig dit en gebruik appointment_intent: true\n- Verwijs bij twijfel naar de klantenservice`;

const messages = [
  ...history,
  { role: 'user', content: validated.message }
];

return [{ json: {
  sessionId: validated.sessionId,
  companyId: validated.companyId,
  userMessage: validated.message,
  claudeBody: {
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 1024,
    system: systemPrompt,
    tools: [{
      name: 'chatbot_response',
      description: 'Geef een gestructureerde chatbot respons',
      input_schema: {
        type: 'object',
        properties: {
          answer: {
            type: 'string',
            description: 'Het antwoord voor de gebruiker'
          },
          appointment_intent: {
            type: 'boolean',
            description: 'Wil de gebruiker een afspraak boeken?'
          },
          preferred_datetime: {
            type: 'string',
            description: 'Gewenste datum/tijd als appointment_intent true is'
          }
        },
        required: ['answer', 'appointment_intent']
      }
    }],
    tool_choice: { type: 'tool', name: 'chatbot_response' },
    messages
  }
} }];

const resp = $('Roep Claude Aan').item.json;
const meta = $('Bouw AI Prompt').item.json;

const toolUse = (resp.content || []).find(c => c.type === 'tool_use');
const input = toolUse ? toolUse.input : {};

const answer = input.answer || 'Sorry, ik kon geen antwoord genereren. Probeer het opnieuw.';
const appointmentIntent = input.appointment_intent === true;
const preferredDatetime = input.preferred_datetime || null;

return [{ json: {
  sessionId: meta.sessionId,
  companyId: meta.companyId,
  userMessage: meta.userMessage,
  answer,
  appointmentIntent,
  preferredDatetime
} }];

parameters.body:
